import time
from functools import wraps
from typing import Any, Callable, Tuple, Type

def retry(max_attempts: int = 3, backoff_factor: float = 2.0, exceptions: Tuple[Type[Exception], ...] = (Exception,)) -> Callable:
    """
    Decorator that retries a function on failure with exponential backoff.

    :param max_attempts: Maximum number of attempts to make before giving up.
    :param backoff_factor: Factor by which the delay between attempts will increase after each failed attempt.
    :param exceptions: Tuple of exception types that should be retried on.
    """
    def decorator(func: Callable) -> Callable:
        @wraps(func)
        def wrapper(*args, **kwargs) -> Any:
            delay = 1
            for _ in range(max_attempts):
                try:
                    return func(*args, **kwargs)
                except exceptions as e:
                    print(f"Function {func.__name__} failed with error: {e}. Retrying after {delay} seconds...")
                    time.sleep(delay)
                    delay *= backoff_factor
            return func(*args, **kwargs)
        return wrapper
    return decorator
```

You can use this decorator like so:

```python
@retry(max_attempts=3, backoff_factor=2, exceptions=(Exception,))
def unreliable_function():
    # This function may raise an exception.
    pass
```

This will retry `unreliable_function` up to 3 times with exponential backoff if it raises an exception. The delay between attempts starts at 1 second and doubles after each failed attempt. If the function has a return value, that value is returned by the decorator.

